/**
 * @name OS Command Injection via Runtime.exec or ProcessBuilder
 * @description User-controlled input flowing to OS command execution
 * @kind path-problem
 * @problem.severity error
 * @id java/os-command-injection
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module CmdInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Runtime.exec with string argument
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // ProcessBuilder constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // ProcessBuilder.command()
    exists(MethodCall mc |
      mc.getMethod().hasName("command") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module CmdInjectionFlow = TaintTracking::Global<CmdInjectionConfig>;
import CmdInjectionFlow::PathGraph

from CmdInjectionFlow::PathNode source, CmdInjectionFlow::PathNode sink
where CmdInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "OS command injection from $@.", source.getNode(), "user input"

/**
 * @name Taint flow from Jenkins job parameters to command execution
 * @description Jenkins build parameters or environment values flowing to command execution
 * @kind path-problem
 * @problem.severity error
 * @id java/jenkins-param-to-cmd
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module JenkinsCmdConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Any RemoteFlowSource
    source instanceof RemoteFlowSource
    or
    // Jenkins-specific: getParameter, getEnvironment, env variables
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getParameter") or
        mc.getMethod().hasName("getEnvironment") or
        mc.getMethod().hasName("getValue") or
        mc.getMethod().hasName("getDescriptor")
      ) and
      source.asExpr() = mc
    )
    or
    // Fields from build configuration (typically populated via Stapler/config forms)
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().getAnAncestor().hasQualifiedName("hudson.tasks", "BuildWrapper") and
      (
        mc.getMethod().hasName("get*") or
        mc.getMethod().hasName("is*")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ProcessBuilder constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Runtime.exec
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Array element assigned to cmdArgs that goes into exec
    exists(ArrayAccess aa |
      aa.getArray().(VarAccess).getVariable().hasName("cmdArgs") and
      sink.asExpr() = aa
    )
  }
}

module JenkinsCmdFlow = TaintTracking::Global<JenkinsCmdConfig>;
import JenkinsCmdFlow::PathGraph

from JenkinsCmdFlow::PathNode source, JenkinsCmdFlow::PathNode sink
where JenkinsCmdFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Command injection from $@.", source.getNode(), "user-controlled input"

/**
 * @name Taint flow from PerfectoBuildWrapper fields to command execution
 * @description Trace flow from user-configurable fields to command execution in getTunnelId
 * @kind path-problem
 * @problem.severity error
 * @id java/perfecto-field-to-cmd
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking

module FieldToCmdConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Any field access on PerfectoBuildWrapper instance (user-configured fields via Stapler)
    exists(FieldAccess fa |
      fa.getField().getDeclaringType().hasName("PerfectoBuildWrapper") and
      source.asExpr() = fa
    )
    or
    // Method calls that return user-configured values (getters)
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().hasName("PerfectoBuildWrapper") and
      mc.getMethod().getName().matches("get%") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ProcessBuilder constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Runtime.exec
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module FieldToCmdFlow = TaintTracking::Global<FieldToCmdConfig>;
import FieldToCmdFlow::PathGraph

from FieldToCmdFlow::PathNode source, FieldToCmdFlow::PathNode sink
where FieldToCmdFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Command injection: field $@ flows to command execution.", source.getNode(), "user-configured field"
